interface Props {
  card: Card
  searchResult?: SearchResult
  viewMode?: 'grid' | 'list'
  gridColumns?: number
  isSelected?: boolean
  showSelection?: boolean
  onSelect?: () => void
}

export function CardGridItem({
  card,
  searchResult,
  viewMode = 'grid',
  gridColumns = 4,
  isSelected = false,
  showSelection = false,
  onSelect,
}: Props) {
  const hoverTimeoutRef = useRef<NodeJS.Timeout | null>(null)
  const { showHoverAtPosition, hideHover, isMobile } = useCardHover()

  const canShowHover = viewMode === 'grid' && !isMobile && gridColumns >= 4

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (hoverTimeoutRef.current) clearTimeout(hoverTimeoutRef.current)
    }
  }, [])

  const handleMouseEnter = (e: React.MouseEvent) => {
    if (!canShowHover) return
    if (hoverTimeoutRef.current) clearTimeout(hoverTimeoutRef.current)
    const { clientX, clientY } = e
    hoverTimeoutRef.current = setTimeout(() => {
      showHoverAtPosition(card, searchResult, clientX, clientY)
    }, 700)
  }

  const handleMouseLeave = () => {
    if (!canShowHover) return
    if (hoverTimeoutRef.current) {
      clearTimeout(hoverTimeoutRef.current)
      hoverTimeoutRef.current = null
    }
    hideHover()
  }

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData(
      'application/json',
      JSON.stringify({ id: card.id, name: card.name, game: card.game?.code })
    )
    e.dataTransfer.effectAllowed = 'copy'
    if (hoverTimeoutRef.current) {
      clearTimeout(hoverTimeoutRef.current)
      hoverTimeoutRef.current = null
    }
    hideHover()
  }

  return (
    <div
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
    >
      <CardDisplay
        card={card}
        searchResult={searchResult}
        variant={viewMode === 'list' ? 'list' : 'grid'}
        isSelected={isSelected}
        showSelection={showSelection}
        onSelect={onSelect}
        draggable={true}
        onDragStart={handleDragStart}
      />
    </div>
  )
}

